    80→class APIServerRepository extends Repository {
    81→  static final _fc =
    82→      failureCodeBuilder.category('DASR'); // Data-ApiServerRepository
    83→  static final _logger = FimberLog('APIServerRepository');
    84→  static const _searchCountLimit = 10000;
    85→
    86→  final ProfileStorage profileStorage;
    87→  late final APIServerClient _client;
    88→
    89→  APIServerRepository({
    90→    required this.profileStorage,
    91→    required Locale locale,
    92→    required String? appVersion,
    93→  }) {
    94→    _client = APIServerClient(
    95→      locale: locale,
    96→      appVersion: appVersion,
    97→    );
    98→  }
    99→
   100→  ResourceData _reprocessResource(
   101→    ResourceData resource,
   102→    String teamId,
   103→    String sessionId,
   104→    String? userId,
   105→  ) {
   106→    return resource.copyWith(
   107→      teamId: teamId,
   108→      sessionId: sessionId,
   109→      userId: userId ?? resource.userId,
   110→    );
   111→  }
   112→
   113→  ResourceData _reprocessResourceWithBallInfo(
   114→    ResourceData resource,
   115→    String teamId,
   116→    String sessionId,
   117→    String? userId,
   118→  ) {
   119→    final ballInfoList = resource.ballInfoList!.toList()
   120→      ..retainWhere((ballInfo) =>
   121→          (ballInfo.ball.isPitched ?? false) || (ballInfo.ball.isHit ?? false));
   122→
   123→    return _reprocessResource(
   124→      resource.copyWith(ballInfoList: ballInfoList),
   125→      teamId,
   126→      sessionId,
   127→      userId,
   128→    );
   129→  }
   130→
   131→  @override
   132→  Future<Result<Failure, SessionSearchResponse>> getSessions({
   133→    required int page,
   134→    required int pageSize,
   135→    required bool isTeamCrossing,
   136→    String? location,
   137→    String? playerId,
   138→    DateTime? startDate,
   139→    DateTime? endDate,
   140→  }) async {
   141→    final methodFc = _fc.category('GSS');
   142→
   143→    final userId = profileStorage.getUserId();
   144→    final userTeamId = profileStorage.getTeamId();
   145→    if (userId == null || userTeamId == null) {
   146→      // NOTE: This happens by logging out and logging back in again
   147→      return Left(Failure.undefined(code: methodFc.position('001')));
   148→    }
   149→
   150→    // Use the isTeamCrossing parameter passed from the caller
   151→    final response = await _client.request(
   152→      method: 'POST',
   153→      path: '/teams/$userTeamId/sessions/search',
   154→      data: SessionSearchRequest(
   155→        page: page,
   156→        pageSize: pageSize,
   157→        userId: isTeamCrossing ? null : userId,
   158→        playerId: playerId,
   159→        location: location,
   160→        dateFrom: startDate?.toUtc(),
   161→        dateTo: endDate?.toUtc(),
   162→        orderBy: SessionSearchRequestOrderBy.createdAt,
   163→        isOrderDesc: true,
   164→      ).toJson(),
   165→      responseMapper: SessionSearchResponse.fromJson,
   166→    );
   167→    if (response.hasLeft) {
   168→      return Left(response.left);
   169→    }
   170→    return Right(response.right);
   171→  }
   172→
   173→  @override
   174→  Future<Result<Failure, List<String>>> getSessionLocations({
   175→    required bool isTeamCrossing,
   176→  }) async {
   177→    final methodFc = _fc.category('GSL');
   178→
   179→    final userId = profileStorage.getUserId();
   180→    final userTeamId = profileStorage.getTeamId();
   181→    if (userId == null || userTeamId == null) {
   182→      // NOTE: This happens by logging out and logging back in again
   183→      return Left(Failure.undefined(code: methodFc.position('001')));
   184→    }
   185→
   186→    final response = await _client.request(
   187→      method: 'GET',
   188→      path: '/teams/$userTeamId/sessions/locations',
   189→      queryParameters: {
   190→        if (!isTeamCrossing) 'userId': userId,
   191→      },
   192→      responseMapper: SessionLocationsResponse.fromJson,
   193→    );
   194→    if (response.hasLeft) {
   195→      return Left(response.left);
   196→    }
   197→    return Right(response.right.locations);
   198→  }
   199→
   200→  @override
   201→  Future<Result<Failure, Session>> getSessionDetail({
   202→    required String teamId,
   203→    required String sessionId,
   204→  }) async {
   205→    final response = await _client.request(
   206→      method: 'GET',
   207→      path: '/teams/$teamId/sessions/$sessionId',
   208→      responseMapper: SessionDetailResponse.fromJson,
   209→    );
   210→    if (response.hasLeft) {
   211→      return Left(response.left);
   212→    }
   213→    return Right(response.right.session);
   214→  }
   215→
   216→  @override
   217→  Future<Result<Failure, PlayerSearchResponse>> getPlayers({
   218→    required int page,
   219→    required int pageSize,
   220→    required bool isTeamCrossing,
   221→  }) async {
   222→    final userId = profileStorage.getUserId();
   223→    final userTeamId = profileStorage.getTeamId();
   224→    // Use the isTeamCrossing parameter passed from the caller
   225→    final response = await _client.request(
   226→      method: 'POST',
   227→      path: '/teams/$userTeamId/players/search',
   228→      data: PlayerSearchRequest(
   229→        page: page,
   230→        pageSize: pageSize,
   231→        userId: isTeamCrossing ? null : userId,
   232→        orderBy: PlayerSearchRequestOrderBy.name,
   233→      ).toJson(),
   234→      responseMapper: PlayerSearchResponse.fromJson,
   235→    );
   236→    if (response.hasLeft) {
   237→      return Left(response.left);
   238→    }
   239→    return Right(response.right);
   240→  }
   241→
   242→  @override
   243→  Future<Result<Failure, ResourceSearchResponse>> getResources({
   244→    required String teamId,
   245→    required String sessionId,
   246→    required int page,
   247→    required int pageSize,
   248→    required bool isTeamCrossing,
   249→  }) async {
   250→    final userId = profileStorage.getUserId();
   251→    final response = await _client.request(
   252→      method: 'POST',
   253→      path: '/teams/$teamId/sessions/$sessionId/resources/search',
   254→      data: ResourceSearchRequest(
   255→        userId: isTeamCrossing ? null : userId,
   256→        page: page,
   257→        pageSize: pageSize,
   258→        orderBy: ResourceSearchRequestOrderBy.createdAt,
   259→        isOrderDesc: true,
   260→      ).toJson(),
   261→      responseMapper: ResourceSearchResponse.fromJson,
   262→    );
   263→    if (response.hasLeft) {
   264→      return Left(response.left);
   265→    }
   266→
   267→    return Right(
   268→      response.right.copyWith(
   269→        resources: response.right.resources
   270→            .map(
   271→              (resource) => _reprocessResourceWithBallInfo(
   272→                resource,
   273→                teamId,
   274→                sessionId,
   275→                resource.session?.userId,
   276→              ),
   277→            )
   278→            .toList(),
   279→      ),
   280→    );
   281→  }
   282→
   283→  @override
   284→  Future<Result<Failure, ResourceData>> getResourceDetail({
   285→    required String teamId,
   286→    required String sessionId,
   287→    required String resourceId,
   288→  }) async {
   289→    final response = await _client.request(
   290→      method: 'GET',
   291→      path: '/teams/$teamId/sessions/$sessionId/resources/$resourceId',
   292→      responseMapper: ResourceDetailResponse.fromJson,
   293→    );
   294→
   295→    if (response.hasLeft) {
   296→      return Left(response.left);
   297→    }
   298→
   299→    final resourceData = _reprocessResourceWithBallInfo(
   300→      response.right.resource,
   301→      teamId,
   302→      sessionId,
   303→      response.right.resource.session?.userId,
   304→    );
   305→
   306→    return Right(resourceData);
   307→  }
   308→
   309→  @override
   310→  Future<Result<Failure, Ball>> getBall({
   311→    required String teamId,
   312→    required String sessionId,
   313→    required String resourceId,
   314→    required int ballId,
   315→  }) async {
   316→    final response = await _client.request(
   317→      method: 'GET',
   318→      path:
   319→          '/teams/$teamId/sessions/$sessionId/resources/$resourceId/balls/$ballId',
   320→      responseMapper: BallResponse.fromJson,
   321→    );
   322→    if (response.hasLeft) {
   323→      return Left(response.left);
   324→    }
   325→    return Right(response.right.ball);
   326→  }
   327→
   328→  @override
   329→  Future<Result<Failure, List<PitchType>>> getPitchTypes() async {
   330→    final response = await _client.request(
   331→      method: 'GET',
   332→      path: '/pitch-types',
   333→      responseMapper: PitchTypeResponse.fromJson,
   334→    );
   335→    if (response.hasLeft) {
   336→      return Left(response.left);
   337→    }
   338→    return Right(response.right.pitchTypes);
   339→  }
   340→
   341→  @override
   342→  Future<Result<Failure, UserInfo>> getUserInfo() async {
   343→    final response = await _client.request(
   344→      method: 'GET',
   345→      path: '/users/me',
