    final methodFc = _fc.category('UPPT');

    final mimeType = lookupMimeType(filePath);
    if (mimeType == null) {
      _logger.w(
          'failed to lookup mimetype for extension: ${filePath.split('.').last}');
      return Left(Failure.undefined(
        code: methodFc.position('001'),
      ));
    }

    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$teamId/players/$playerId/thumbnail',
      data: FormData.fromMap({
        'file': await MultipartFile.fromFile(
          filePath,
          contentType: MediaType.parse(mimeType),
        ),
      }),
      responseMapper: PlayerImageUploadResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.url);
  }

  @override
  Future<Result<Failure, String>> uploadVideo({
    required String sessionId,
    required String resourceId,
    required String filePath,
    required UnitType unit,
    required int analyzeType,
    required String? cameraMode,
    required double? focalLengthIn35mmEquivalent,
    required double? longsideAngleOfView,
    required double? accX,
    required double? accY,
    required double? accZ,
    required String? lens,
    required double? focus,
    required bool? isAutoFocus,
    required double? zoom,
    required double? iso,
    required double? shutterSpeed,
    required String? device,
    required DateTime? recordedAt,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.uploadInBackground(
      method: 'POST',
      path: '/teams/$teamId/sessions/$sessionId/resources/analyze',
      data: VideoAnalyzeRequest(
        resourceId: resourceId,
        recordedAt: recordedAt?.toUtc(),
        analyzeType: analyzeType,
        longsideAngleOfView: longsideAngleOfView,
        focalLength: focalLengthIn35mmEquivalent,
        accX: accX,
        accY: accY,
        accZ: accZ,
        lens: lens,
        focus: focus,
        isAutoFocus: isAutoFocus,
        zoom: zoom,
        iso: iso,
        shutterSpeed: shutterSpeed,
        device: device,
        unit: unit,
        cameraMode: cameraMode,
      ).toJson(),
      fileField: 'file',
      filePath: filePath,
      responseMapper: VideoAnalyzeResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.resource.id);
  }

  @override
  Future<Result<Failure, void>> reAnalyzeVideo({
    required String sessionId,
    required String resourceId,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'PUT',
      path: '/teams/$teamId/sessions/$sessionId/resources/$resourceId/analyze',
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return const Right(null);
  }

  @override
  Future<Result<Failure, EditMemberRoleResponse>> editMemberRole({
    required String userId,
    required AppRole role,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'PUT',
      path: '/teams/$teamId/users/$userId/user-roles',
      data: EditMemberRoleRequest(
        role: role,
      ).toJson(),
      responseMapper: EditMemberRoleResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, void>> inviteMember({
    required String name,
    required String email,
    required AppRole role,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$teamId/users/invite',
      data: InviteMemberRequest(
        userName: name,
        email: email,
        role: role,
        // NOTE: Send dummy URL to enforce default URL
        redirectTo: 'http://redirect.invalid/',
      ).toJson(),
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return const Right(null);
  }

  @override
  Future<Result<Failure, DeactivateMemberResponse>> deactivateMember({
    required String userId,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'PUT',
      path: '/teams/$teamId/users/$userId/deactivate',
      responseMapper: DeactivateMemberResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, ReactivateMemberResponse>> reactivateMember({
    required String userId,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'PUT',
      path: '/teams/$teamId/users/$userId/activate',
      responseMapper: ReactivateMemberResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, VerifyTransactionResponse>> verifyTransaction({
    required String transactionId,
    required String webOrderLineItemId,
  }) async {
    final teamId = profileStorage.getTeamId();
    final response = await _client.request(
      method: 'POST',
      path: '/teams/$teamId/payment-sessions/apple/subscription',
      data: {
        'transactionId': transactionId,
        'webOrderLineItemId': webOrderLineItemId,
      },
      responseMapper: VerifyTransactionResponse.fromJson,
    );

    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, TeamDeactivateResponse>> deactivateTeam({
    required String teamId,
  }) async {
    final response = await _client.request(
      method: 'PUT',
      path: '/teams/$teamId/deactivate',
      responseMapper: TeamDeactivateResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }

    return Right(response.right);
  }

  @override
  Future<Result<Failure, String>> createAIReport({
    required String teamId,
    required String sessionId,
  }) async {
    final response = await _client.request(
        method: 'POST',
        path: '/teams/$teamId/ai-coach-reports',
        data: {
          'sessionId': sessionId,
        });
    if (response.hasLeft) {
      return Left(response.left);
    }
    final reportId = response.right['id'] as String;
    return Right(reportId);
  }

  @override
  Future<Result<Failure, AICoachReport>> getAIReport({
    required String teamId,
    required String reportId,
  }) async {
    final response = await _client.request(
      method: 'GET',
      path: '/teams/$teamId/ai-coach-reports/$reportId',
      responseMapper: AICoachReport.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right);
  }

  @override
  Future<Result<Failure, List<SubscriptionGroup>>> getSubscriptionGroups() async {
    final response = await _client.request(
      method: 'GET',
      path: '/subscription-groups',
      responseMapper: SubscriptionGroupsResponse.fromJson,
    );
    if (response.hasLeft) {
      return Left(response.left);
    }
    return Right(response.right.subscriptionGroups);
  }
}

